+            type: 'string',
+          },
+          req2: {
+            type: 'string',
+          },
+        },
+      };
+      data = {};
+      ajv.validate(schema, data);
+      const errors = betterAjvErrors({ data, schema, errors: ajv.errors });
+      expect(errors).toEqual([
+        {
+          context: {
+            errorType: 'required',
+          },
+          message: "{base} must have required property 'req1'",
+          path: '{base}',
